define i32 @neg_sub_plus_mul_pow2(i32 %x, i32 %y) {
  %a = sub i32 %x, %y
  %b = mul i32 %y, 8
  %c = add i32 %a, %b
  ret i32 %c
}

define i32 @sub_plus_mul(i32 %x, i32 %y) {
  %a = sub i32 %x, %y
  %b = mul i32 %y, 10
  %c = add i32 %a, %b
  ret i32 %c
}

define i32 @sub_plus_mul3(i32 %x, i32 %y) {
  %a = mul i32 %y, 10
  %b = sub i32 %x, %y
  %c = add i32 %b, %a
  ret i32 %c
}

define i32 @sub_plus_mul4(i32 %x, i32 %y) {
  %a = mul i32 %y, -10
  %b = sub i32 %x, %y
  %c = add i32 %b, %a
  ret i32 %c
}

define i32 @sub_plus_mul_2(i32 %x, i32 %y) {
  %a = sub i32 %x, %y
  %b = mul i32 %y, -10
  %c = add i32 %a, %b
  ret i32 %c
}

define <2 x i8> @sub_plus_mul_splat(<2 x i8> %x, <2 x i8> %y) {
  %a = sub <2 x i8> %x, %y
  %b = mul <2 x i8> %y, <i8 7, i8 7>
  %c = add <2 x i8> %a, %b
  ret <2 x i8> %c
}
